previewCss:
.darma-loader-uiverse-matrix-rain-digits {
  width: fit-content;
  height: fit-content;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.darma-loader-uiverse-matrix-rain-digits__ai-matrix-loader {
width: 120px;
height: 160px;
margin: 30px auto;
position: relative;
perspective: 800px;
display: grid;
grid-template-columns: repeat(3, 1fr);
gap: 5px;
}

.darma-loader-uiverse-matrix-rain-digits__digit {
color: #00ff88;
font-family: monospace;
font-size: 18px;
text-align: center;
text-shadow: 0 0 5px #00ff88;
animation:
darma-loader-uiverse-matrix-rain-digits-matrix-fall 2s infinite,
darma-loader-uiverse-matrix-rain-digits-matrix-flicker 0.5s infinite;
opacity: 0;
}

.darma-loader-uiverse-matrix-rain-digits__digit:nth-child(1) {
animation-delay: 0.1s;
}
.darma-loader-uiverse-matrix-rain-digits__digit:nth-child(2) {
animation-delay: 0.3s;
}
.darma-loader-uiverse-matrix-rain-digits__digit:nth-child(3) {
animation-delay: 0.5s;
}
.darma-loader-uiverse-matrix-rain-digits__digit:nth-child(4) {
animation-delay: 0.7s;
}
.darma-loader-uiverse-matrix-rain-digits__digit:nth-child(5) {
animation-delay: 0.9s;
}
.darma-loader-uiverse-matrix-rain-digits__digit:nth-child(6) {
animation-delay: 1.1s;
}
.darma-loader-uiverse-matrix-rain-digits__digit:nth-child(7) {
animation-delay: 1.3s;
}
.darma-loader-uiverse-matrix-rain-digits__digit:nth-child(8) {
animation-delay: 1.5s;
}

.darma-loader-uiverse-matrix-rain-digits__glow {
position: absolute;
top: 0;
left: 0;
right: 0;
bottom: 0;
background: radial-gradient(
circle,
rgba(0, 255, 136, 0.1) 0%,
transparent 70%
);
animation: darma-loader-uiverse-matrix-rain-digits-matrix-pulse 2s infinite;
}

@keyframes darma-loader-uiverse-matrix-rain-digits-matrix-fall {
0% {
transform: translateY(-50px) rotateX(90deg);
opacity: 0;
}
20%,
80% {
transform: translateY(0) rotateX(0deg);
opacity: 0.8;
}
100% {
transform: translateY(50px) rotateX(-90deg);
opacity: 0;
}
}

@keyframes darma-loader-uiverse-matrix-rain-digits-matrix-flicker {
0%,
19%,
21%,
100% {
opacity: 0.8;
}
20% {
opacity: 0.2;
}
}

@keyframes darma-loader-uiverse-matrix-rain-digits-matrix-pulse {
0%,
100% {
opacity: 0.3;
}
50% {
opacity: 0.7;
}
}

